SELECT professional_id, last_name, cell_number FROM Professionals WHERE state = 'Indiana'
UNION
SELECT p.professional_id, p.last_name, p.cell_number FROM Professionals p INNER JOIN Treatments t ON p.professional_id = t.professional_id GROUP BY p.professional_id, p.last_name, p.cell_number HAVING COUNT(t.treatment_id) > 2;
